const data = $input.first().json;
const text  = data.text  || data.body || data.content || '';
const title = data.title || '';

if (!text) throw new Error('No text provided');

const now  = new Date();
const pad  = n => String(n).padStart(2, '0');
const ts   = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}_${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
const heading = title || ts;
const dateStr = now.toISOString().replace('T', ' ').substring(0, 19) + ' UTC';

const content = `# ${heading}\n\n${text}\n\n---\ncaptured: ${dateStr}\n`;
const filename = `/mnt/docs/Local-Network-Hub/03-Inbox/${ts}.md`;

const fs = require('fs');
fs.writeFileSync(filename, content, 'utf8');

return [{ json: { ok: true, file: filename, title: heading } }];
